PART = '        frame = 1 + round(t * (total_frames - 1))\n        phase = t * math.tau * (3.0 if is_run else 2.0)\n        swing = math.sin(phase)\n        opposite = math.sin(phase + math.pi)\n        bounce = abs(math.sin(phase)) * (0.08 if is_run else 0.045)\n        jump_height = math.sin(math.pi * t) * 0.78 if is_jump else 0.0\n\n        key_pose(\n            pose["root"],\n            frame,\n            rotation=(0.0, 0.0, math.radians(3.0) * math.sin(phase * 0.5)),\n            location=(travel * t, 0.0, bounce + jump_height),\n        )\n        key_pose(pose["pelvis"], frame, rotation=(math.radians(2) * swing, math.radians(4) * swing, math.radians(6) * swing))\n        key_pose(pose["spine"], frame, rotation=(math.radians(-3) * swing, 0.0, math.radians(-5) * swing))\n        key_pose(pose["chest"], frame, rotation=(math.radians(3) * swing, 0.0, math.radians(4) * opposite))\n        key_pose(\n            pose["neck"],\n            frame,\n            rotation=(math.radians(-4) * bounce * 8.0, 0.0, math.radians(3) * swing),\n        )\n        head_z = math.radians(-9 if is_angry else 5) * math.sin(phase * 0.5)\n        head_x = math.radians(-10 if is_surprised else 3) * math.sin(phase * 0.25)\n        key_pose(pose["head"], frame, rotation=(head_x, 0.0, head_z))\n\n        key_pose(pose["upper_arm.L"], frame, rotation=(stride * opposite, 0.0, math.radians(-4)))\n        key_pose(pose["upper_arm.R"], frame, rotation=(stride * swing, 0.0, math.radians(4)))\n        key_pose(pose["forearm.L"], frame, rotation=(math.radians(-18) - max(0.0, swing) * math.radians(22), 0.0, 0.0))\n        key_pose(pose["forearm.R"], frame, rotation=(math.radians(-18) - max(0.0, opposite) * math.radians(22), 0.0, 0.0))\n        key_pose(pose["hand.L"], frame, rotation=(math.radians(8) * swing, 0.0, 0.0))\n        key_pose(pose["hand.R"], frame, rotation=(math.radians(8) * opposite, 0.0, 0.0))\n\n        key_pose(pose["thigh.L"], frame, rotation=(stride * swing, 0.0, 0.0))\n        key_pose(pose["thigh.R"], frame, rotation=(stride * opposite, 0.0, 0.0))\n        key_pose(pose["shin.L"], frame, rotation=(max(0.0, -swing) * math.radians(48), 0.0, 0.0))\n        key_pose(pose["shin.R"], frame, rotation=(max(0.0, -opposite) * math.radians(48), 0.0, 0.0))\n        key_pose(pose["foot.L"], frame, rotation=(math.radians(-12) * swing, 0.0, 0.0))\n        key_pose(pose["foot.R"], frame, rotation=(math.radians(-12) * opposite, 0.0, 0.0))\n\n        jaw_open = 0.0\n        if is_surprised:\n            jaw_open = math.radians(18) * max(0.0, math.sin(math.pi * t))\n        elif is_laugh:\n            jaw_open = math.radians(13) * (0.35 + 0.65 * abs(math.sin(phase * 0.5)))\n        key_pose(pose["jaw"], frame, rotation=(jaw_open, 0.0, 0.0))\n\n        blink = 0.14 if (sample % 7 == 5) else 1.0\n        eye_scale = (1.0, 1.0, blink)\n        key_pose(pose["eye.L"], frame, rotation=(0.0, 0.0, math.radians(4) * swing), scale=eye_scale)\n        key_pose(pose["eye.R"], frame, rotation=(0.0, 0.0, math.radians(4) * swing), scale=eye_scale)\n        key_pose(pose["ear.L"], frame, rotation=(math.radians(5) * opposite, 0.0, math.radians(-3)))\n        key_pose(pose["ear.R"], frame, rotation=(math.radians(5) * swing, 0.0, math.radians(3)))\n\n        for index in range(1, 6):\n            tail_phase = phase * 0.65 - index * 0.55\n            key_pose(\n                pose[f"tail.{index:02d}"],\n                frame,\n                rotation=(math.radians(4) * math.sin(tail_phase * 0.8), math.radians(6) * math.cos(tail_phase), math.radians(18) * math.sin(tail_phase)),\n            )\n\n    camera.location = (5.8, -10.2, 4.2)\n    point_camera(camera, Vector((0.7, 0.0, 1.35)))\n    camera.keyframe_insert(data_path="location", frame=1)\n    camera.keyframe_insert(data_path="rotation_euler", frame=1)\n    camera.data.lens = 52\n    camera.data.keyframe_insert(data_path="lens", frame=1)\n\n    camera.location = (travel + 4.8, -8.6, 3.6)\n    point_camera(camera, Vector((travel, 0.0, 1.45)))\n    camera.keyframe_insert(data_path="location", frame=total_frames)\n    camera.keyframe_insert(data_path="rotation_euler", frame=total_frames)\n    camera.data.lens = 58\n    camera.data.keyframe_insert(data_path="lens", frame=total_frames)\n    set_interpolation(rig, camera)\n\n\ndef configure_scene():\n    scene = bpy.context.scene\n    timeline = JOB["timeline"]\n    render = JOB["render"]\n    scene.frame_start = 1\n    scene.frame_end = max(2, int(timeline["total_frames"]))\n    scene.render.fps = int(timeline["fps"])\n    scene.render.resolution_x = int(render["width"])\n    scene.render.resolution_y = int(render["height"])\n    scene.render.resolution_percentage = int(render.get("preview_resolution_percentage", 100))\n\n    preferred_engine = str(render.get("engine", "BLENDER_WORKBENCH"))\n    engine_candidates = [preferred_engine, "BLENDER_WORKBENCH", "BLENDER_EEVEE_NEXT", "BLENDER_EEVEE"]\n    for engine_name in engine_candidates:\n        try:\n            scene.render.engine = engine_name\n            break\n        except Exception:\n            continue\n\n    if scene.render.engine == "BLENDER_WORKBENCH":\n        scene.display.shading.light = "STUDIO"\n        scene.display.shading.color_type = "MATERIAL"\n        scene.display.shading.show_shadows = True\n        scene.display.shading.show_cavity = True\n        scene.display.shading.cavity_type = "WORLD"\n        scene.display.shading.show_specular_highlight = True\n\n    scene.render.image_settings.file_format = "FFMPEG"\n    scene.render.ffmpeg.format = "MPEG4"\n    scene.render.ffmpeg.codec = "H264"\n    scene.render.ffmpeg.constant_rate_factor = "MEDIUM"\n    scene.render.ffmpeg.ffmpeg_preset = "GOOD"\n'